import { useState } from 'react';

import api from '../services/api'
import Button from '@mui/material/Button';
import CircularProgress from '@mui/material/CircularProgress';

export default function Acao() {

    const [executando, setExecutando] = useState(false)

    function executarAcao(id) {
        setExecutando(true);
        api.get('/acao/' + id).then(resp => {setExecutando(false)})
    }

    const usuario = JSON.parse(localStorage.getItem('usuario'))

    return (<div>
        {executando && <div style={{display: 'flex', alignItems: 'center', justifyContent: 'center',}}><CircularProgress color="secondary" /></div>}
        {usuario.roles.map(role => role.acaos.map(acao => <Button key={acao.id} style={{width: '200px', margin: "10px"}} onClick={() => executarAcao(acao.id)} variant="contained">{acao.nome}</Button>))}
        </div>
    )
}
