import { useEffect } from 'react'
import { HashRouter as Router, Route, Routes } from 'react-router-dom'

import { AuthProvider, useAuth } from './contexts/auth';
import Gerente from './pages/Gerente';
import Login from "./pages/Login";
import Acao from "./pages/Acao";
import LoginInvalido from "./pages/LoginInvalido";
import ServidorIndisponivel from "./pages/ServidorIndisponivel";
import Header from "./pages/Header";

import { createTheme, ThemeProvider } from '@mui/material/styles';
import { deepOrange } from '@mui/material/colors';


const theme = createTheme({
  palette: {
    primary: {
      main: deepOrange[800],
    },
  },
});

export default function App() {
  useEffect(() => {
    document.title = process.env.REACT_APP_TITTLE
  }, []);


  return (
    <ThemeProvider theme={theme}>
      <AuthProvider>
        <Header />
        <Router>
          <Routes>
            <Route element={<Login />} path="/" />
            <Route element={<Login />} path="/login" />
            <Route element={<Gerente />} path="/gerente" />
            <Route element={<Acao />} path="/quarto" />
            <Route element={<LoginInvalido />} path="/loginInvalido" />
            <Route element={<ServidorIndisponivel />} path="/servidorIndisponivel" />
          </Routes>
        </Router>
      </AuthProvider>
    </ThemeProvider>
  );
};